# Attack rate from the SIR final-size relation (perfect pre-vaccination)
attack_rate &lt;- function(pi, R0) {
    Reff &lt;- R0 * (1 - pi)
    if (Reff &lt;= 1) {
        return(0)
    }
    w &lt;- uniroot(
        \(w) w - (1 - exp(-Reff * w)),
        interval = c(1e-8, 1 - 1e-8)
    )$root
    (1 - pi) * w
}

# Planner's per-capita loss
loss &lt;- function(pi, R0, cv = 0.10, ci = 1.0) {
    cv * pi + ci * attack_rate(pi, R0)
}

# Worst-case loss over R0 in [R_lo, R_hi]
worst_case &lt;- function(pi, R_lo, R_hi, cv, ci) {
    R_grid &lt;- seq(R_lo, R_hi, length.out = 60)
    max(sapply(R_grid, \(R0) loss(pi, R0, cv, ci)))
}

# Minimax coverage: minimises the worst-case loss
minimax_pi &lt;- function(R_lo, R_hi, cv = 0.10, ci = 1.0) {
    optimize(\(pi) worst_case(pi, R_lo, R_hi, cv, ci),
        interval = c(0, 1)
    )$minimum
}

# Bayes coverage: minimises expected loss under a truncated-normal prior
bayes_pi &lt;- function(R0_mean, R0_sd, R_lo = 1.1, R_hi = 20,
                     cv = 0.10, ci = 1.0, n = 500) {
    R0_samples &lt;- rtruncnorm(n,
        a = R_lo, b = R_hi,
        mean = R0_mean, sd = R0_sd
    )
    optimize(
        \(pi) mean(sapply(R0_samples, \(R0) loss(pi, R0, cv, ci))),
        interval = c(0, 1)
    )$minimum
}

# Nash coverage from Part 1 (linear pi_inf)
nash_coverage &lt;- function(R0, q, r) {
    pi_c &lt;- 1 - 1 / R0
    if (r &gt;= q) {
        return(0)
    }
    uniroot(
        \(pi) q * pmax(0, 1 - pi / pi_c) - r,
        interval = c(0, pi_c)
    )$root
}

2.2 Box-Cox Transformation
The Box-Cox transformation is particularly useful when you want to transform data to approximate normality before matching moments.


Code
boxcox_match &lt;- function(A, B) {
  # Find optimal lambda for both distributions
  bc_A &lt;- boxcox(A ~ 1, plotit = FALSE)
  lambda_A &lt;- bc_A$x[which.max(bc_A$y)]

  # Transform to normality
  transform_boxcox &lt;- function(x, lambda) {
    if (abs(lambda) &lt; 1e-4) {
      log(x)
    } else {
      (x^lambda - 1) / lambda
    }
  }

  # Transform both samples
  A_transformed &lt;- transform_boxcox(A, lambda_A)
  B_transformed &lt;- transform_boxcox(B, lambda_A)  # Use same lambda

  # Match moments
  B_standardized &lt;- (B_transformed - mean(B_transformed)) / sd(B_transformed)
  B_matched &lt;- B_standardized * sd(A_transformed) + mean(A_transformed)

  # Inverse transform
  inverse_boxcox &lt;- function(x, lambda) {
    if (abs(lambda) &lt; 1e-4) {
      exp(x)
    } else {
      (lambda * x + 1)^(1/lambda)
    }
  }

  B_final &lt;- inverse_boxcox(B_matched, lambda_A)
  return(B_final)
}

2.3 Kernel Density-Based Transformation
This method uses kernel density estimation to transform the distributions.


Code
kernel_density_match &lt;- function(A, B, bw = "nrd0") {
  # Estimate densities
  density_A &lt;- kde(A, h = bw.nrd0(A))
  density_B &lt;- kde(B, h = bw.nrd0(B))

  # Calculate CDFs using numerical integration
  cdf_A &lt;- function(x) {
    sapply(x, function(xi) {
      mean(pnorm(xi, A, density_A$h))
    })
  }

  cdf_B &lt;- function(x) {
    sapply(x, function(xi) {
      mean(pnorm(xi, B, density_B$h))
    })
  }

  # Transform B to match A's distribution
  B_probs &lt;- cdf_B(B)

  # Create quantile function for A using interpolation
  A_sorted &lt;- sort(A)
  A_probs &lt;- cdf_A(A_sorted)

  B_transformed &lt;- approx(x = A_probs,
                         y = A_sorted,
                         xout = B_probs,
                         yleft = min(A),
                         yright = max(A))$y

  return(B_transformed)
}

2.4 Moment Matching
A simpler approach that focuses on matching the first two moments of the distributions.


Code
moment_match &lt;- function(A, B) {
  # Standardize B
  B_std &lt;- (B - mean(B)) / sd(B)

  # Transform to match A's moments
  B_transformed &lt;- B_std * sd(A) + mean(A)

  return(B_transformed)
}

