lhs_sample &lt;- function(n, p) {
  # Returns n x p matrix; each column is a LHS draw on [0, 1]
  mat &lt;- matrix(NA_real_, nrow = n, ncol = p)
  for (j in seq_len(p)) {
    mat[, j] &lt;- (sample(n) - runif(n)) / n
  }
  mat
}

